#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Level;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Enemies;
using MVZ2.GameContent.Stages;
using MVZ2Logic;
using MVZ2Logic.IZombie;
using PVZEngine;
using PVZEngine.Level;
using Tools;
using UnityEngine;
using PVZEngine.Buffs;

namespace MVZ2.GameContent.IZombie
{
    [IZombieLayoutDefinition(VanillaIZombieLayoutNames.BlackholeHarbor)]
    public class BlackholeHarborLayout : IZombieLayoutDefinition
    {
        public BlackholeHarborLayout(string nsp, string name) : base(nsp, name, 5)
        {
            Blueprints = new NamespaceID[]
            {
                VanillaEnemyID.popCaptain,
                VanillaContraptionID.blackHoleBomb,
                VanillaEnemyID.berserker,
                VanillaEnemyID.imp
            };
        }
        public override void Fill(IIZombieMap map, RandomGenerator rng)
        {
            Insert(map, 0, 0, VanillaContraptionID.furnace);
            Insert(map, 0, 1, VanillaContraptionID.mineTNT);

            Insert(map, 1, 0, VanillaContraptionID.thunderDrum);
            Insert(map, 1, 1, VanillaContraptionID.drivenser);
            Insert(map, 1, 3, VanillaContraptionID.furnace);
            Insert(map, 1, 4, VanillaContraptionID.spikeBlock);

            Insert(map, 2, 2, VanillaContraptionID.elasticCloud);

            Insert(map, 3, 4, VanillaContraptionID.elasticCloud);

            Insert(map, 4, 1, VanillaContraptionID.furnace);
            Insert(map, 4, 2, VanillaContraptionID.teslaCoil);
            Insert(map, 4, 2, VanillaContraptionID.stoneShield);
            Insert(map, 4, 3, VanillaContraptionID.furnace);
            Insert(map, 4, 4, VanillaContraptionID.teslaCoil);

            var level = map.Level;
            SpawnAt(level, 5, 2, VanillaContraptionID.elasticCloud);
            SpawnAt(level, 5, 3, VanillaContraptionID.blackHoleBomb);
            SpawnAt(level, 5, 4, VanillaContraptionID.elasticCloud);

            //SpawnAt(level, 3, 2, VanillaEffectID.redline);

            var rlX = level.GetColumnX(3);       // 列左边缘，与标准红线一致  
            var rlZ = level.GetLaneCenterZ(2);   // lane 3 的中心  
            var rlY = level.GetGroundY(rlX, rlZ);

            level.Spawn(VanillaEffectID.redline, new Vector3(rlX, rlY, rlZ), null);

            var buffDef = level.Content.GetBuffDefinition<DebugNoRechargeBuff>();
            if (!level.HasBuff(buffDef))
            {
                level.AddBuff(buffDef);
            }

        }
        private void SpawnAt(LevelEngine level, int column, int lane, NamespaceID entityID)
        {
            var x = level.GetEntityColumnX(column);
            var z = level.GetEntityLaneZ(lane);
            var y = level.GetGroundY(x, z);
            level.Spawn(entityID, new Vector3(x, y, z), null);
        }
    }
}
